func (r *Rope) Len() int {
    if r == nil {
        return 0
    }
    return r.weight + r.right.Len()
}

func (r *Rope) Index(i int) byte {
    if i < r.weight {
        if r.left == nil {
            return r.value[i]
        }
        return r.left.Index(i)
    }
    return r.right.Index(i - r.weight)
}

